 1→server {
 2→    listen 80;
 3→    root /usr/share/nginx/html;
 4→    index index.html;
 5→
 6→    # Allow large uploads (MP3 + image)
 7→    client_max_body_size 200M;
 8→
 9→    # Generous timeouts — transcription with Whisper can take several minutes
10→    proxy_read_timeout    600s;
11→    proxy_connect_timeout  30s;
12→    proxy_send_timeout    600s;
13→
14→    # Proxy all /api/* requests to the FastAPI backend
15→    location /api/ {
16→        proxy_pass         http://backend:8000;
17→        proxy_http_version 1.1;
18→        proxy_set_header   Host              $host;
19→        proxy_set_header   X-Real-IP         $remote_addr;
20→        proxy_set_header   X-Forwarded-For   $proxy_add_x_forwarded_for;
21→        proxy_set_header   X-Forwarded-Proto $scheme;
22→        # Disable buffering for streaming downloads
23→        proxy_buffering    off;
24→    }
25→
26→    # SPA fallback — let React Router handle all non-file routes
27→    location / {
28→        try_files $uri $uri/ /index.html;
29→    }
30→}
